import React, { useEffect, useState } from 'react';
import api from '../services/api';
import VoteButton from './VoteButton';
import AnswerForm from './AnswerForm';
import CommentForm from './CommentForm';
import TagList from './TagList';           // ← This was missing → fixed the 'TagList is not defined' error

const QuestionDetail = ({ questionId }) => {
  const [question, setQuestion] = useState(null);
  const [answers, setAnswers] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  useEffect(() => {
    const fetchData = async () => {
      try {
        setLoading(true);
        setError(null);

        // Fetch question
        const qRes = await api.get(`/questions/${questionId}`);
        setQuestion(qRes.data);

        // Fetch answers
        const aRes = await api.get(`/answers?questionId=${questionId}`);
        setAnswers(aRes.data || []);
      } catch (err) {
        console.error('Error fetching question/answers:', err);
        setError('Failed to load question. Please try again later.');
      } finally {
        setLoading(false);
      }
    };

    if (questionId) {
      fetchData();
    }
  }, [questionId]);

  const acceptAnswer = async (answerId) => {
    if (!localStorage.getItem('token')) {
      alert('You must be logged in to accept an answer.');
      return;
    }

    try {
      await api.put(
        `/questions/${questionId}/accept`,
        { answerId },
        {
          headers: { Authorization: `Bearer ${localStorage.getItem('token')}` },
        }
      );
      // Refresh data after accepting
      window.location.reload();
    } catch (err) {
      console.error('Error accepting answer:', err);
      alert('Failed to accept answer. Try again.');
    }
  };

  if (loading) return <div>Loading question...</div>;

  if (error) return <div style={{ color: 'red' }}>{error}</div>;

  if (!question) return <div>Question not found</div>;

  const currentUserId = localStorage.getItem('userId'); // might be string or null

  return (
    <div>
      <h1>{question.title}</h1>
      <p>{question.body}</p>

      <VoteButton type="question" id={question._id} votes={question.votes || 0} />

      {/* Tags */}
      {question.tags && question.tags.length > 0 && (
        <TagList tags={question.tags} />
      )}

      <h2>Answers ({answers.length})</h2>

      {answers.length === 0 ? (
        <p>No answers yet. Be the first to answer!</p>
      ) : (
        answers
          .sort((a, b) => {
            // Accepted answer first, then by votes descending
            if (question.acceptedAnswer === a._id) return -1;
            if (question.acceptedAnswer === b._id) return 1;
            return b.votes - a.votes;
          })
          .map((answer) => (
            <div
              key={answer._id}
              style={{
                border: '1px solid #ddd',
                padding: '16px',
                margin: '16px 0',
                borderRadius: '8px',
                background: question.acceptedAnswer === answer._id ? '#f0fff4' : 'white',
              }}
            >
              <p>{answer.body}</p>

              <VoteButton type="answer" id={answer._id} votes={answer.votes || 0} />

              {question.acceptedAnswer === answer._id && (
                <strong style={{ color: 'green', marginLeft: '10px' }}>Accepted ✓</strong>
              )}

              {question.author &&
                String(question.author) === String(currentUserId) &&
                !question.acceptedAnswer && (
                  <button
                    onClick={() => acceptAnswer(answer._id)}
                    style={{ marginLeft: '10px', background: '#28a745', color: 'white' }}
                  >
                    Accept this answer
                  </button>
                )}

              <CommentForm postId={answer._id} type="answer" />
              {/* You can later add rendering of existing comments here */}
            </div>
          ))
      )}

      <h3>Your Answer</h3>
      <AnswerForm questionId={questionId} />

      <h3>Comments on Question</h3>
      <CommentForm postId={question._id} type="question" />
    </div>
  );
};

export default QuestionDetail;
